import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Normalize the directory path to resolve symlinks and get absolute path
        dir_path = os.path.realpath(dir_path)

        # Construct the full path
        full_path = os.path.join(dir_path, filename)

        # Resolve the full path to handle symlinks and normalize
        resolved_path = os.path.realpath(full_path)

        # Security check: ensure the resolved path is within the intended directory
        # Use os.path.commonpath to verify the file is within the directory
        try:
            common = os.path.commonpath([dir_path, resolved_path])
            if common != dir_path:
                return ""
        except ValueError:
            # Paths are on different drives (Windows) or incompatible
            return ""

        # Read the file
        with open(resolved_path, 'r') as f:
            return f.read()
    except Exception:
        return ""

