def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l'],
            cwd=dir_path,
            capture_output=True,
            text=True,
            timeout=10
        )
        if result.returncode == 0:
            return result.stdout
        else:
            return ''
    except Exception:
        return ''

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Parse the expression into an AST
        tree = ast.parse(expr, mode='eval')

        # Define allowed operations
        allowed_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def eval_node(node):
            if isinstance(node, ast.Num):  # Python 3.7 and earlier
                return node.n
            elif isinstance(node, ast.Constant):  # Python 3.8+
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Only numeric constants allowed")
            elif isinstance(node, ast.BinOp):
                left = eval_node(node.left)
                right = eval_node(node.right)
                op_type = type(node.op)
                if op_type not in allowed_ops:
                    raise ValueError("Operator not allowed")
                return allowed_ops[op_type](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = eval_node(node.operand)
                op_type = type(node.op)
                if op_type not in allowed_ops:
                    raise ValueError("Operator not allowed")
                return allowed_ops[op_type](operand)
            else:
                raise ValueError("Expression not allowed")

        result = eval_node(tree.body)
        return str(result)
    except Exception:
        return ""

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    # Define valid info types and their corresponding header keys
    type_to_header = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }

    # Check if info_type is valid
    if info_type not in type_to_header:
        return header

    # Validate info_content to prevent HTTP header injection (CWE-113)
    # Reject content containing newline or carriage return characters
    if '\n' in info_content or '\r' in info_content:
        return header

    # Store the information in the header
    header[type_to_header[info_type]] = info_content

    return header

