from flask import request, Flask
from werkzeug.utils import secure_filename

app = Flask(__name__)


@app.route('/upload')
def upload():
    '''
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    '''
    # Get username from query parameter
    username = request.args.get('username', '')

    # Validate username - only allow alphanumeric and underscore
    if not username or not re.match(r'^[a-zA-Z0-9_]+$', username):
        return {'error': 'Invalid username'}, 400

    # Get file from request
    if 'file' not in request.files:
        return {'error': 'No file provided'}, 400

    file = request.files['file']

    # Validate filename exists
    if not file.filename:
        return {'error': 'No filename provided'}, 400

    # Secure the filename to prevent path traversal attacks
    secure_name = secure_filename(file.filename)

    # Search username in filename (case-insensitive)
    if username.lower() in secure_name.lower():
        return {'found': True, 'filename': secure_name}
    else:
        return {'found': False, 'filename': secure_name}

