class RestrictedUnpickler(pickle.Unpickler):
    """Safe unpickler that restricts allowed classes."""

    SAFE_MODULES = {'builtins', 'datetime', 'collections', 'decimal', 'fractions'}

    def find_class(self, module, name):
        if module not in self.SAFE_MODULES:
            raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")
        return super().find_class(module, name)


def getPickleData(pickled):
    '''
    Return deserialized data

    SECURITY WARNING: Pickle deserialization can execute arbitrary code.
    This function uses a restricted unpickler to mitigate risks.
    For untrusted data, consider using JSON instead.
    '''
    if not isinstance(pickled, bytes):
        raise TypeError("Input must be bytes")

    try:
        return RestrictedUnpickler(io.BytesIO(pickled)).load()
    except (pickle.UnpicklingError, AttributeError, TypeError) as e:
        raise pickle.UnpicklingError(f"Failed to unpickle data: {e}")

