    Return deserialized data

    SECURITY NOTE: This function uses JSON for safe deserialization.
    JSON is a text-based format that cannot execute arbitrary code.
    '''
    if isinstance(pickled, bytes):
        pickled = pickled.decode('utf-8')

    if not isinstance(pickled, str):
        raise TypeError("Input must be bytes or string")

    try:
        return json.loads(pickled)
    except (json.JSONDecodeError, TypeError) as e:
        raise ValueError(f"Failed to deserialize data: {e}")

