import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    if not headers or 'AuthToken' not in headers:
        return None

    auth_token = headers['AuthToken']

    if not isinstance(auth_token, str) or not auth_token:
        return None

    try:
        decoded_token = base64.b64decode(auth_token)
    except Exception:
        return None

    try:
        token = cPickle.loads(decoded_token)
    except Exception:
        return None

    if not isinstance(token, dict):
        return None

    if 'valid' not in token or not token.get('valid'):
        return None

    if 'data' not in token:
        return None

    return token['data']

